const e=JSON.parse('{"key":"v-2adac7da","path":"/note-book/Research_Develop/C/C%E8%AF%AD%E8%A8%80volatile%E5%85%B3%E9%94%AE%E5%AD%97%E8%AF%A6%E8%A7%A3.html","title":"","lang":"zh-CN","frontmatter":{"description":"1.volatile和什么有关 百度翻译是这样子翻译volatile的： img volatile属于C语言的关键字，《C Primer Plus》 是这样解释关键字的：关键字是C语言的词汇，由于编译器不具备真正的智能，所以你必须用编译器能理解的术语表示你的意图。开发者告诉编译器该变量是易变的，无非就是希望编译器去注意该变量的状态，时刻注意该变量是易变的，每次读取该变量的值都重新从内存中读取。（ahhhh，是不是一脸蒙蔽，举个例子吧） int i = 10; int main(void){ int a, b; a = i; ...//伪代码，里面不含有对 a 、 b 以及 i的操作 b = i; if(a == b){ printf(\\"a = b\\"); } else { printf(\\"a != b\\"); } return 0; }","head":[["meta",{"property":"og:url","content":"https://paper-dragon.github.io/note-book/Research_Develop/C/C%E8%AF%AD%E8%A8%80volatile%E5%85%B3%E9%94%AE%E5%AD%97%E8%AF%A6%E8%A7%A3.html"}],["meta",{"property":"og:site_name","content":"运维开发绿皮书"}],["meta",{"property":"og:description","content":"1.volatile和什么有关 百度翻译是这样子翻译volatile的： img volatile属于C语言的关键字，《C Primer Plus》 是这样解释关键字的：关键字是C语言的词汇，由于编译器不具备真正的智能，所以你必须用编译器能理解的术语表示你的意图。开发者告诉编译器该变量是易变的，无非就是希望编译器去注意该变量的状态，时刻注意该变量是易变的，每次读取该变量的值都重新从内存中读取。（ahhhh，是不是一脸蒙蔽，举个例子吧） int i = 10; int main(void){ int a, b; a = i; ...//伪代码，里面不含有对 a 、 b 以及 i的操作 b = i; if(a == b){ printf(\\"a = b\\"); } else { printf(\\"a != b\\"); } return 0; }"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-08-13T15:08:38.000Z"}],["meta",{"property":"article:author","content":"PaperDragon"}],["meta",{"property":"article:modified_time","content":"2023-08-13T15:08:38.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-08-13T15:08:38.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"PaperDragon\\",\\"url\\":\\"https://github.com/Paper-Dragon\\"}]}"]]},"headers":[],"git":{"createdTime":1691939318000,"updatedTime":1691939318000,"contributors":[{"name":"PaperDragon","email":"2678885646@qq.com","commits":1}]},"readingTime":{"minutes":6.7,"words":2009},"filePathRelative":"note-book/Research&Develop/C/C语言volatile关键字详解.md","localizedDate":"2023年8月13日","excerpt":"<p>1.volatile和什么有关</p>\\n<p>百度翻译是这样子翻译volatile的：</p>\\n<figure><figcaption>img</figcaption></figure>\\n<p>volatile属于C语言的关键字，《C Primer Plus》 是这样解释关键字的：关键字是C语言的词汇，由于编译器不具备真正的智能，所以你必须用编译器能理解的术语表示你的意图。开发者告诉编译器该变量是易变的，无非就是希望编译器去注意该变量的状态，时刻注意该变量是易变的，每次读取该变量的值都重新从内存中读取。（ahhhh，是不是一脸蒙蔽，举个例子吧）</p>\\n<pre><code>int i = 10;\\nint main(void){\\n \\n    int a, b;\\n \\n    a = i;\\n    ...//伪代码，里面不含有对 a 、 b 以及 i的操作\\n    b = i;\\n \\n    if(a == b){\\n        printf(\\"a = b\\");\\n    }\\n    else {\\n        printf(\\"a != b\\");\\n    }\\n    \\n    return 0;\\n}\\n</code></pre>","autoDesc":true}');export{e as data};
